import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class TokenPurchaseOkParser implements IMessageParser {
    private _tokenId: number = 0;
    private _diamonds: number = 0;
    private _activeUntilTs: number = 0;

    public flush(): boolean {
        this._tokenId = 0;
        this._diamonds = 0;
        this._activeUntilTs = 0;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        this._tokenId = wrapper.readInt();
        this._diamonds = wrapper.readInt();
        this._activeUntilTs = wrapper.readInt(); // 0 when token is just added to inventory

        return true;
    }

    public get tokenId(): number {
        return this._tokenId;
    }
    public get diamonds(): number {
        return this._diamonds;
    }
    public get activeUntilTs(): number {
        return this._activeUntilTs;
    }
}
